#ifndef BUZZER_MUSIC_H
#define BUZZER_MUSIC_H

#include "main.h"

// 音符频率定义
#define NOTE_C4  262
#define NOTE_D4  294
#define NOTE_E4  330
#define NOTE_F4  349
#define NOTE_G4  392
#define NOTE_A4  440
#define NOTE_B4  494
#define NOTE_C5  523
#define NOTE_D5  587
#define NOTE_E5  659
#define NOTE_F5  698
#define NOTE_G5  784
#define NOTE_A5  880
#define NOTE_B5  988

// 定义音符和持续时间
typedef struct {
    uint16_t freq;
    uint16_t duration;
} music_note_t;

// “鸡你太美”音乐简谱 - 修正版
static const music_note_t jntm_score[] = {
    {NOTE_A4, 150}, {NOTE_A4, 150}, {NOTE_A4, 150}, {NOTE_G4, 300},
    {NOTE_A4, 150}, {NOTE_G4, 150}, {NOTE_A4, 300}, {0, 150},
    {NOTE_E4, 150}, {NOTE_E4, 150}, {NOTE_E4, 150}, {NOTE_D4, 300},
    {NOTE_E4, 150}, {NOTE_D4, 150}, {NOTE_E4, 300}, {0, 300},
};

void play_music(const music_note_t* score, uint16_t score_size);

#endif //BUZZER_MUSIC_H

#ifndef BUZZER_MUSIC_H
#define BUZZER_MUSIC_H

#include "main.h"

// 音符频率定义
#define NOTE_C4  262
#define NOTE_D4  294
#define NOTE_E4  330
#define NOTE_F4  349
#define NOTE_G4  392
#define NOTE_A4  440
#define NOTE_B4  494
#define NOTE_C5  523
#define NOTE_D5  587
#define NOTE_E5  659
#define NOTE_F5  698
#define NOTE_G5  784
#define NOTE_A5  880
#define NOTE_B5  988

// 定义音符和持续时间
typedef struct {
    uint16_t freq;
    uint16_t duration;
} music_note_t;

// “鸡你太美”音乐简谱 - 修正版
static const music_note_t jntm_score[] = {
    {NOTE_A4, 150}, {NOTE_A4, 150}, {NOTE_A4, 150}, {NOTE_G4, 300},
    {NOTE_A4, 150}, {NOTE_G4, 150}, {NOTE_A4, 300}, {0, 150},
    {NOTE_E4, 150}, {NOTE_E4, 150}, {NOTE_E4, 150}, {NOTE_D4, 300},
    {NOTE_E4, 150}, {NOTE_D4, 150}, {NOTE_E4, 300}, {0, 300},
};

void play_music(const music_note_t* score, uint16_t score_size);

#endif //BUZZER_MUSIC_H

#include "buzzer_music.h"
#include "bsp_tim.h"
#include "cmsis_os.h"

/**
  * @brief          播放音乐
  * @param[in]      score: 乐谱指针
  * @param[in]      score_size: 乐谱大小
  * @retval         无
  */
void play_music(const music_note_t* score, uint16_t score_size)
{
    for (int i = 0; i < score_size; i++)
    {
        if (score[i].freq > 0)
        {
            // 设置PWM频率和占空比来发出声音
            // 假设 bsp_tim.h 中有 buzzer_on 函数
            // 定时器时钟为84MHz, 84000000 / freq = arr
            buzzer_on(84000000 / score[i].freq, 500); // 50% duty cycle
        }
        else
        {
            // 频率为0表示休止符
            buzzer_off();
        }
        // 延迟以控制音符的持续时间
        osDelay(score[i].duration);
    }
    // 播放完毕后关闭蜂鸣器
    buzzer_off();
}

